const https = require('https');
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const hostname = supabaseUrl.replace('https://', '');

function httpsGet(opts) {
  return new Promise((resolve, reject) => {
    const req = https.get(opts, (res) => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, data: JSON.parse(body) });
        } catch (e) {
          resolve({ status: res.statusCode, data: body });
        }
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('timeout')); });
  });
}

try {
  const today = new Date().toISOString().split('T')[0];

  // Check if already posted today
  const postsToday = await httpsGet({
    hostname,
    path: `/rest/v1/blog_posts?select=id&created_at=gte.${today}T00:00:00Z&created_at=lt.${today}T23:59:59Z&limit=1`,
    headers: {
      'apikey': supabaseKey,
      'Authorization': 'Bearer ' + supabaseKey
    }
  });

  if (Array.isArray(postsToday.data) && postsToday.data.length > 0) {
    return [{ json: { skip: true, reason: 'Already posted today' } }];
  }

  // Fetch last 10 English blog post titles for dedup
  const recentRes = await httpsGet({
    hostname,
    path: '/rest/v1/blog_post_translations?locale=eq.en&select=title&order=created_at.desc&limit=10',
    headers: {
      'apikey': supabaseKey,
      'Authorization': 'Bearer ' + supabaseKey
    }
  });

  const recentTitles = Array.isArray(recentRes.data) ? recentRes.data.map(r => r.title) : [];

  // Determine template type by day of week
  const dayOfWeek = new Date().getUTCDay();
  let templateType = 'quick-take';
  if (dayOfWeek >= 1 && dayOfWeek <= 4) templateType = 'quick-take';
  else if (dayOfWeek === 5) templateType = 'analysis';
  else if (dayOfWeek === 6) templateType = 'meme';
  else if (dayOfWeek === 0) templateType = 'roundup';

  return [{ json: { skip: false, recentTitles, templateType, today } }];
} catch (e) {
  return [{ json: { skip: false, recentTitles: [], templateType: 'quick-take', today: new Date().toISOString().split('T')[0], error: String(e) } }];
}

const https = require('https');

const RSS_FEEDS = [
  { name: 'Asia Times', url: 'https://asiatimes.com/feed/' },
  { name: 'EFF', url: 'https://www.eff.org/rss/updates.xml' },
  { name: 'Rest of World', url: 'https://restofworld.org/feed/' },
  { name: 'TorrentFreak', url: 'https://torrentfreak.com/feed/' },
  { name: 'The Record', url: 'https://therecord.media/feed' },
  { name: 'Freedom House', url: 'https://freedomhouse.org/rss.xml' },
  { name: 'Meduza EN', url: 'https://meduza.io/rss/en/all' },
  { name: 'Novaya Gazeta EU', url: 'https://novayagazeta.eu/rss/all' },
  { name: 'The Insider', url: 'https://theins.ru/rss' }
];

const MAX_PER_FEED = 10;
const TIMEOUT_MS = 15000;
const MAX_REDIRECTS = 3;
const USER_AGENT = 'Doppler Editorial Bot/1.0';

function decodeEntities(str) {
  if (!str) return '';
  return str
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#039;/g, "'")
    .replace(/&apos;/g, "'")
    .replace(/&quot;/g, '"');
}

function stripHtml(str) {
  if (!str) return '';
  return str.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
}

function fetchUrl(url, redirectCount) {
  if (redirectCount === undefined) redirectCount = 0;
  return new Promise((resolve, reject) => {
    const proto = url.startsWith('https') ? https : require('http');
    const req = proto.get(url, { headers: { 'User-Agent': USER_AGENT } }, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location && redirectCount < MAX_REDIRECTS) {
        let redirectUrl = res.headers.location;
        if (redirectUrl.startsWith('/')) {
          const parsed = new URL(url);
          redirectUrl = parsed.origin + redirectUrl;
        }
        resolve(fetchUrl(redirectUrl, redirectCount + 1));
        return;
      }
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => resolve(body));
    });
    req.on('error', () => resolve(''));
    req.setTimeout(TIMEOUT_MS, () => { req.destroy(); resolve(''); });
  });
}

function parseItems(xml) {
  const items = [];
  const itemRegex = /<item[\s>][\s\S]*?<\/item>/gi;
  let match;
  while ((match = itemRegex.exec(xml)) !== null) {
    const block = match[0];
    const titleMatch = block.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s);
    const linkMatch = block.match(/<link>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s);
    const pubDateMatch = block.match(/<pubDate>(.*?)<\/pubDate>/s);
    const descMatch = block.match(/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s);
    if (titleMatch && linkMatch) {
      items.push({
        title: decodeEntities(stripHtml(titleMatch[1])),
        url: decodeEntities(linkMatch[1].trim()),
        pubDate: pubDateMatch ? pubDateMatch[1].trim() : '',
        description: descMatch ? decodeEntities(stripHtml(descMatch[1])).substring(0, 500) : ''
      });
    }
  }
  return items;
}

const now = Date.now();
const oneDayAgo = now - 24 * 60 * 60 * 1000;
const seenUrls = new Set();
const allArticles = [];

for (const feed of RSS_FEEDS) {
  try {
    const xml = await fetchUrl(feed.url);
    if (!xml) continue;
    const items = parseItems(xml);
    let count = 0;
    for (const item of items) {
      if (count >= MAX_PER_FEED) break;
      if (seenUrls.has(item.url)) continue;

      // Filter to last 24 hours
      if (item.pubDate) {
        const pubTime = new Date(item.pubDate).getTime();
        if (!isNaN(pubTime) && pubTime < oneDayAgo) continue;
      }

      seenUrls.add(item.url);
      allArticles.push({
        title: item.title,
        url: item.url,
        source: feed.name,
        summary: item.description
      });
      count++;
    }
  } catch (e) {
    // Skip failed feeds silently
    continue;
  }
}

return [{ json: { articles: allArticles, articleCount: allArticles.length } }];

