const recentTitles = $('Preflight Check').first().json.recentTitles || [];
const templateType = $('Preflight Check').first().json.templateType || 'quick-take';

const articleList = articles.map((a, i) => `${i}. [${a.source}] ${a.title}
   ${a.summary ? a.summary.substring(0, 150) : '(no summary)'}
   URL: ${a.url}`).join('

');

const recentList = recentTitles.length > 0 ? recentTitles.map(t => `- ${t}`).join('
') : '(none)';

const systemPrompt = `You are an editorial assistant for Doppler VPN's tech blog. Your job is to pick ONE article from the list below that is most relevant and newsworthy for a VPN/privacy/tech audience.

TOPIC PRIORITIES (in order):
1. Internet censorship, VPN bans, website blocks
2. Digital privacy, surveillance, data protection
3. AI policy, AI product launches
4. Cybersecurity incidents, vulnerabilities
5. Tech geopolitics, sanctions, regulations
6. Big tech news (Google, Apple, Meta, etc.)

AVOID DUPLICATES — these titles were recently published:
${recentList}

If no article is relevant to privacy/tech/VPN topics, return: {"chosen_index": -1, "chosen_url": "", "chosen_title": "", "topic": "", "reason": "No relevant articles found", "topic_category": ""}

Return ONLY valid JSON:
{"chosen_index": N, "chosen_url": "...", "chosen_title": "...", "topic": "brief description for the writer", "reason": "why this article was chosen", "topic_category": "one of: vpn-privacy, ai-launches, ai-regulation, big-tech, censorship, cybersecurity, us-policy"}`;

const userPrompt = `Today's template type: ${templateType}

Here are ${articles.length} articles from RSS feeds. Pick the single best one:

${articleList}`;

return [{ json: { systemPrompt, userPrompt, templateType, articles } }];

