const input = $input.first().json;
const templateType = $('Build Prompt').first().json.templateType;

// Parse OpenAI response
let content = input.choices[0].message.content;
if (content.startsWith('```')) {
  content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let selection;
try {
  selection = JSON.parse(content);
} catch (e) {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    selection = JSON.parse(match[0]);
  } else {
    return [{ json: { skip: true, reason: 'Failed to parse OpenAI response: ' + content.substring(0, 200) } }];
  }
}

// If no topic selected
if (!selection.topic || selection.topic.trim() === '' || selection.chosen_index === -1) {
  return [{ json: { skip: true, reason: selection.reason || 'No relevant topic found' } }];
}

