    req.end();
  });
}

try {
  html = await fetchHtml(articleUrl);

  if (html) {
    // Extract OG image
    const ogMatch = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i)
      || html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+property=["']og:image["']/i);
    const twitterMatch = html.match(/<meta[^>]+name=["']twitter:image["'][^>]+content=["']([^"']+)["']/i)
      || html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+name=["']twitter:image["']/i);

    let candidateUrl = ogMatch ? ogMatch[1] : (twitterMatch ? twitterMatch[1] : null);

    if (candidateUrl) {
      // Handle relative URLs
      if (candidateUrl.startsWith('/')) {
        const parsed = new URL(articleUrl);
        candidateUrl = parsed.origin + candidateUrl;
      }
      const isValid = await validateImage(candidateUrl);
      if (isValid) imageUrl = candidateUrl;
    }

    // Extract article text
    let textSource = '';
    const articleMatch = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
    if (articleMatch) {
      textSource = articleMatch[1];
    } else {
      textSource = html;
    }

    // Get paragraphs
    const pRegex = /<p[^>]*>([\s\S]*?)<\/p>/gi;
    let pMatch;
    const paragraphs = [];
    while ((pMatch = pRegex.exec(textSource)) !== null) {
      const text = pMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
      if (text.length > 50) paragraphs.push(text);
    }
    articleText = paragraphs.join('\n\n').substring(0, 3000);
  }
} catch (e) {
  // Non-fatal: continue without image/text
}

return [{
  json: {
    skip: false,
    topic: selection.topic,
    headline: selection.chosen_title,
    summary: articleText || selection.topic,
    topicCategory: selection.topic_category || '',
    sources: [articleUrl],
    sourceLinks: [articleUrl],
    templateType,
    imageUrl,
    key_quotes: [],
    date: new Date().toISOString().split('T')[0]
  }
}];

const contentGen = $input.first().json;
const processNode = $('Process Selection + OG Image').first().json;

const merged = {
  ...contentGen,
  imageUrl: contentGen.imageUrl || processNode.imageUrl,
  sourceLinks: processNode.sourceLinks || [],
  topicCategory: processNode.topicCategory || contentGen.topicCategory || '',
  templateType: processNode.templateType || contentGen.templateType || 'quick-take',
  sourcesStr: (processNode.sourceLinks || []).join(', ')
};

return [{ json: merged }];
